class FileWatcher(Thread):
    def __init__(self, directory, callback):
        Thread.__init__(self)
        self.directory = directory
        self.callback = callback
        self.observer = Observer()
        self.handler = MyHandler(directory, callback)

    def run(self):
        self.observer.schedule(self.handler, self.directory, recursive=True)
        self.observer.start()

        try:
            while True:
                time.sleep(1)
        except KeyboardInterrupt:
            self.observer.stop()
            print("File watcher stopped")

        self.observer.join()


class MyHandler(FileSystemEventHandler):
    def __init__(self, directory, callback):
        self.directory = directory
        self.callback = callback

    def on_created(self, event):
        self.on_modified(event)

    def on_modified(self, event):
        filename = event.src_path
        if not os.path.isfile(filename):
            return

        try:
            with open(filename, 'r') as f:
                source = f.read()
                ast.parse(source)
        except SyntaxError:
            # File is not a valid Python script
            return

        try:
            module = inspect.getmodule(source)
        except Exception:
            # File is not a valid module
            return

        self.callback(filename)


def watch_directory(directory, callback):
    file_watcher = FileWatcher(directory, callback)
    file_watcher.start()
    file_watcher.join()

