def check_url_accessibility(url: str, timeout: int = 5) -> Dict[str, Any]:
    """
    Checks whether a URL is accessible and returns its HTTP status code.

    Args:
    url (str): The URL to check.
    timeout (int, optional): The timeout in seconds. Defaults to 5.

    Returns:
    Dict[str, Any]: A dictionary containing the HTTP status code and the content of the response.
    """

    # Check if the URL is a string
    if not isinstance(url, str):
        raise TypeError("URL must be a string")

    try:
        # Try to send a GET request to the URL
        response = requests.get(url, timeout=timeout)

        # Check if the response was successful
        if response.status_code == 200:
            # If the response was successful, return its HTTP status code and content
            return {'status_code': response.status_code, 'content': response.text}
        else:
            # If the response was not successful, return its HTTP status code and reason
            return {'status_code': response.status_code,'reason': response.reason}

    except requests.RequestException as e:
        # If an exception occurred while sending the request, return an error message
        return {'error': str(e)}

    except Exception as e:
        # If any other exception occurred, return an error message
        return {'error': str(e)}

    # If the function has not returned yet, it means that the URL is not accessible
    return {'error': 'URL is not accessible'}
